const submitted = $json('submittedApplications') || [];
const underReview = $json('underReviewApplications') || [];

const formatApp = (app) => `• ${app.merchantName} - $${app.loanAmountRequested} (${app.applicationNumber})`;

const message = `Daily Underwriting Summary

Submitted (${submitted.length}):
${submitted.slice(0, 10).map(formatApp).join('\n')}${submitted.length > 10 ? '\n...and ' + (submitted.length - 10) + ' more' : ''}

Under Review (${underReview.length}):
${underReview.slice(0, 5).map(formatApp).join('\n')}${underReview.length > 5 ? '\n...and ' + (underReview.length - 5) + ' more' : ''}`;

return { message };
